        stmt.setNull(9, java.sql.Types.INTEGER);
    } else {
        stmt.setInt(9, holdingData.getHoldingID().intValue());
    }
    stmt.setString(10, quoteData.getSymbol());
    stmt.executeUpdate();
    stmt.close();
    return getOrderData(conn, orderID.intValue());
