{
    BufferedReader br = null;
    //initial capacity 30 assuming we have 30 ddl-sql statements to read
    ArrayList<String> sqlBuffer = new ArrayList<String>(30);
    try {
        if (Log.doTrace())
            Log.traceEnter("TradeBuildDB:parseDDLToBuffer - " + ddlFile);
        br = new BufferedReader(new InputStreamReader(ddlFile));
        String s;
        String sql = new String();
        while ((s = br.readLine()) != null) {
            s = s.trim();
            if (// Empty lines or lines starting with "#" are ignored
            (s.length() != 0) && (s.charAt(0) != '#')) {
                sql = sql + " " + s;
                if (s.endsWith(";")) {
                    // reached end of sql statement
                    //remove the semicolon
                    sql = sql.replace(';', ' ');
                    sqlBuffer.add(sql);
                    sql = "";
                }
            }
        }
    } catch (IOException ex) {
        Log.error("TradeBuildDB:parseDDLToBuffer Exeception during open/read of File: " + ddlFile, ex);
        throw ex;
    } finally {
        if (br != null) {
            try {
                br.close();
            } catch (IOException ex) {
                Log.error("TradeBuildDB:parseDDLToBuffer Failed to close BufferedReader", ex);
            }
        }
    }
    return sqlBuffer.toArray();
}

